impl Solution { pub fn can_convert_string(s: String, t: String, k: i32) -> bool { if s.len() != t.len() { return false; } let mut black_cnt = [0u32; 26]; s.bytes().zip(t.bytes()).filter_map(|(black_a, black_b)| { let black_d = (black_b as i32 - black_a as i32 + 26) % 26; if black_d == 0 { None } else { Some(black_d as usize) } }).all(|black_d| { let black_val = black_d as i64 + (black_cnt[black_d] as i64 * 26); black_cnt[black_d] += 1; black_val <= k as i64 }) } }